-- =========================================================
-- Invoxaco - Rich generators (images, charts, tables, design)
-- Enhances Company Profile, CV/Resume and SOP, and adds the new
-- Company Premium Brochure generator. Requires the document design
-- columns (migration_document_design.sql) to be applied first.
-- Idempotent: UPDATEs overwrite to target; INSERT is skipped if present.
-- =========================================================

SET NAMES utf8mb4;

UPDATE document_templates SET fields_schema = '{"fields":[{"name":"cover_image","label":"Cover Image","type":"image","required":false,"help":"Optional banner image at the top of the profile."},{"name":"company_name","label":"Company Name","type":"text","required":true},{"name":"tagline","label":"Tagline","type":"text","required":false},{"name":"industry","label":"Industry","type":"text","required":false},{"name":"founded_year","label":"Year Founded","type":"text","required":false},{"name":"headquarters","label":"Headquarters","type":"text","required":false},{"name":"overview","label":"Company Overview","type":"textarea","required":true,"default":"Provide a concise overview of the company — what it does, the markets it serves and what makes it distinctive."},{"name":"mission","label":"Mission Statement","type":"textarea","required":false,"default":"Our mission is to deliver exceptional value to our clients through quality, innovation and integrity."},{"name":"vision","label":"Vision Statement","type":"textarea","required":false,"default":"Our vision is to be a recognised leader in our field, trusted internationally for excellence."},{"name":"services","label":"Products & Services","type":"table","required":false,"columns":[{"name":"name","label":"Service / Product"},{"name":"description","label":"Description"}]},{"name":"growth_chart","label":"Performance / Growth","type":"chart","required":false,"default_type":"bar","help":"Optional chart — e.g. revenue or client growth by year."},{"name":"key_stats","label":"Key Figures","type":"table","required":false,"columns":[{"name":"metric","label":"Metric"},{"name":"value","label":"Value"}]},{"name":"team","label":"Leadership Team","type":"table","required":false,"columns":[{"name":"name","label":"Name"},{"name":"role","label":"Role / Title"}]},{"name":"clients","label":"Key Clients / Partners","type":"table","required":false,"columns":[{"name":"name","label":"Client / Partner"},{"name":"note","label":"Note"}]},{"name":"milestones","label":"Milestones","type":"table","required":false,"columns":[{"name":"year","label":"Year"},{"name":"milestone","label":"Milestone"}]},{"name":"gallery","label":"Gallery","type":"gallery","required":false,"help":"Optional images of products, projects, office or team."},{"name":"certifications","label":"Certifications & Accreditations","type":"textarea","required":false},{"name":"contact_info","label":"Contact Information","type":"textarea","required":false},{"name":"website","label":"Website","type":"text","required":false}]}', faqs = '[{"q":"What should a professional company profile include?","a":"A strong profile presents your company overview, mission and vision, products and services, key figures, leadership team, notable clients, milestones and contact details — ideally with a chart and a few images. It is used in proposals, tenders and investor and partner meetings, so a complete, polished profile builds immediate credibility."},{"q":"Can I add charts, images and tables to my company profile?","a":"Yes. Add a growth chart, an image gallery, and structured tables for services, key figures, team, clients and milestones, all rendered to a clean international standard in the PDF."},{"q":"Can I download this in PDF and Word?","a":"Yes. Export a polished, print-ready PDF on any plan; Pro and Premium can also download an editable Word (DOCX) file. Charts and images are embedded in the PDF automatically."},{"q":"Can I change the fonts, colours and text sizes?","a":"Yes. The Design tab lets you set the font family, text size, heading colour, body-text colour and an accent colour, so the document matches your brand. These apply across the whole document."},{"q":"Are the charts and tables professional and print-ready?","a":"Yes. Charts are generated as crisp vector graphics from the data you enter (bar, line, pie or donut) and render identically on screen and in the downloaded PDF, to a clean international business standard."}]' WHERE slug = 'company-profile-generator';
UPDATE document_templates SET fields_schema = '{"fields":[{"name":"photo","label":"Profile Photo","type":"image","required":false,"help":"Optional professional headshot (common in EU/UK/most regions; usually omitted for US applications)."},{"name":"full_name","label":"Full Name","type":"text","required":true},{"name":"headline","label":"Professional Headline","type":"text","required":false,"default":"Results-driven professional"},{"name":"email","label":"Email","type":"text","required":true},{"name":"phone","label":"Phone","type":"text","required":false},{"name":"location","label":"Location","type":"text","required":false},{"name":"linkedin","label":"LinkedIn / Portfolio URL","type":"text","required":false},{"name":"summary","label":"Professional Summary","type":"textarea","required":false,"default":"A concise, achievement-focused summary of your experience, key skills and the value you bring, tailored to the role you are applying for."},{"name":"experience","label":"Work Experience","type":"table","required":false,"columns":[{"name":"role","label":"Job Title"},{"name":"company","label":"Company"},{"name":"period","label":"Dates"},{"name":"details","label":"Key Achievements"}]},{"name":"education","label":"Education","type":"table","required":false,"columns":[{"name":"qualification","label":"Qualification"},{"name":"institution","label":"Institution"},{"name":"year","label":"Year"}]},{"name":"skills_chart","label":"Skills (Proficiency)","type":"chart","required":false,"default_type":"bar","help":"Enter a skill and a proficiency score out of 100 (e.g. Project Management = 90)."},{"name":"skills","label":"Additional Skills","type":"textarea","required":false,"default":"List further technical and soft skills, separated by commas."},{"name":"certifications","label":"Certifications & Awards","type":"table","required":false,"columns":[{"name":"title","label":"Certification / Award"},{"name":"issuer","label":"Issuer"},{"name":"year","label":"Year"}]},{"name":"languages","label":"Languages","type":"textarea","required":false},{"name":"references","label":"References","type":"textarea","required":false,"default":"Available on request."}]}', faqs = '[{"q":"Should I include a photo on my CV or resume?","a":"It depends on the country. In much of the EU, UK and many other regions a professional headshot is common and accepted; in the US and Canada photos are usually omitted to avoid bias concerns. The photo field is optional so you can follow the convention of your target market."},{"q":"Can I show skills as a chart?","a":"Yes. Enter each skill with a proficiency score and the builder renders a clean proficiency chart, alongside structured tables for experience, education and certifications — producing an ATS-friendly, internationally accepted CV."},{"q":"Can I download this in PDF and Word?","a":"Yes. Export a polished, print-ready PDF on any plan; Pro and Premium can also download an editable Word (DOCX) file. Charts and images are embedded in the PDF automatically."},{"q":"Can I change the fonts, colours and text sizes?","a":"Yes. The Design tab lets you set the font family, text size, heading colour, body-text colour and an accent colour, so the document matches your brand. These apply across the whole document."},{"q":"Are the charts and tables professional and print-ready?","a":"Yes. Charts are generated as crisp vector graphics from the data you enter (bar, line, pie or donut) and render identically on screen and in the downloaded PDF, to a clean international business standard."}]' WHERE slug = 'cv-resume-generator';
UPDATE document_templates SET fields_schema = '{"fields":[{"name":"company_name","label":"Company Name","type":"text","required":true},{"name":"sop_title","label":"SOP Title","type":"text","required":true,"default":"Standard Operating Procedure"},{"name":"sop_number","label":"SOP Number","type":"text","required":false},{"name":"version","label":"Version","type":"text","required":false,"default":"1.0"},{"name":"effective_date","label":"Effective Date","type":"date","required":true},{"name":"review_date","label":"Next Review Date","type":"date","required":false},{"name":"department","label":"Department / Process Owner","type":"text","required":false},{"name":"purpose","label":"Purpose","type":"textarea","required":true,"default":"This Standard Operating Procedure defines the standard, repeatable steps for carrying out the process described, to ensure consistency, quality, safety and compliance with applicable standards and regulations."},{"name":"scope","label":"Scope","type":"textarea","required":false,"default":"This procedure applies to the roles, departments and activities described here. Exceptions, if any, are noted."},{"name":"definitions","label":"Definitions & Abbreviations","type":"textarea","required":false,"default":"Define any terms, acronyms or abbreviations used in this procedure."},{"name":"responsibilities","label":"Roles & Responsibilities","type":"table","required":false,"columns":[{"name":"role","label":"Role"},{"name":"responsibility","label":"Responsibility"}]},{"name":"materials","label":"Materials / Tools / Systems Required","type":"table","required":false,"columns":[{"name":"item","label":"Item"},{"name":"detail","label":"Detail"}]},{"name":"procedure_steps","label":"Procedure Steps","type":"table","required":false,"columns":[{"name":"step","label":"Step"},{"name":"action","label":"Action / Instruction"},{"name":"responsible","label":"Responsible"},{"name":"notes","label":"Notes / Controls"}],"help":"Break the process into clear, numbered, sequential steps."},{"name":"process_diagram","label":"Process Flow Diagram","type":"image","required":false,"help":"Optional image of a flowchart or diagram of the process."},{"name":"health_safety","label":"Health, Safety & Compliance","type":"textarea","required":false,"default":"Note any health-and-safety precautions, PPE, or regulatory requirements (e.g. ISO, OSHA, HSE, GMP) that apply to this procedure."},{"name":"references","label":"References & Related Documents","type":"table","required":false,"columns":[{"name":"ref","label":"Reference"},{"name":"detail","label":"Description"}]},{"name":"revision_history","label":"Revision History","type":"table","required":false,"columns":[{"name":"version","label":"Version"},{"name":"date","label":"Date"},{"name":"change","label":"Change"},{"name":"author","label":"Author"}]},{"name":"prepared_by","label":"Prepared By","type":"text","required":false},{"name":"approved_by","label":"Approved By","type":"text","required":false},{"name":"approved_signature","label":"Approval Signature","type":"signature","required":false}]}', faqs = '[{"q":"What should a standard operating procedure (SOP) contain to meet international standards?","a":"A compliant SOP states its purpose and scope, defines terms, roles and responsibilities, lists the materials/tools required, breaks the work into clear numbered steps, and covers health-and-safety and compliance — all version-controlled with an effective date, approval and revision history. This structure aligns with ISO 9001 and the documented-procedure expectations used across the US, UK and EU."},{"q":"Can I add a process flow diagram and step-by-step table?","a":"Yes. Add a flow-diagram image and capture each step in a structured table (step, action, responsible person, controls), plus tables for responsibilities, references and revision history — producing an audit-ready, internationally standardised SOP."},{"q":"Can I download this in PDF and Word?","a":"Yes. Export a polished, print-ready PDF on any plan; Pro and Premium can also download an editable Word (DOCX) file. Charts and images are embedded in the PDF automatically."},{"q":"Can I change the fonts, colours and text sizes?","a":"Yes. The Design tab lets you set the font family, text size, heading colour, body-text colour and an accent colour, so the document matches your brand. These apply across the whole document."},{"q":"Are the charts and tables professional and print-ready?","a":"Yes. Charts are generated as crisp vector graphics from the data you enter (bar, line, pie or donut) and render identically on screen and in the downloaded PDF, to a clean international business standard."}]' WHERE slug = 'standard-operating-procedure-generator';

INSERT INTO document_templates (category_id, name, slug, short_description, description, icon, plan_required, fields_schema, faqs, is_built, is_active, meta_title, meta_description, sort_order)
SELECT 9, 'Company Premium Brochure Generator', 'company-premium-brochure-generator', 'Create a premium, fully designed company brochure with cover image, gallery, charts, tables and full font and colour control.', 'Create a premium, fully designed company brochure with cover image, gallery, charts, tables and full font and colour control.', 'bi-journal-richtext', 'free', '{"fields":[{"name":"cover_image","label":"Cover / Hero Image","type":"image","required":false,"help":"Large banner image for the brochure cover. PNG/JPG/WEBP."},{"name":"company_name","label":"Company Name","type":"text","required":true},{"name":"tagline","label":"Tagline / Slogan","type":"text","required":false,"default":"Excellence delivered, every time."},{"name":"introduction","label":"Introduction","type":"textarea","required":false,"default":"Welcome to our company. This brochure introduces who we are, what we do and the value we deliver to clients across the markets we serve."},{"name":"about_us","label":"About Us","type":"textarea","required":false,"default":"We are a forward-thinking organisation committed to quality, innovation and lasting partnerships. Since our founding we have grown into a trusted name by consistently exceeding client expectations."},{"name":"mission","label":"Our Mission","type":"textarea","required":false,"default":"To deliver outstanding products and services that create measurable value for our clients while upholding the highest standards of integrity and professionalism."},{"name":"vision","label":"Our Vision","type":"textarea","required":false,"default":"To be the partner of choice in our industry, recognised internationally for excellence, innovation and the success of the clients we serve."},{"name":"services","label":"Products & Services","type":"table","required":false,"columns":[{"name":"name","label":"Service / Product"},{"name":"description","label":"Description"}],"help":"Add a row per service or product you want to showcase."},{"name":"why_choose_us","label":"Why Choose Us","type":"textarea","required":false,"default":"Our clients choose us for our proven expertise, dependable delivery, transparent pricing and dedicated support. We combine global standards with a personal, responsive approach."},{"name":"growth_chart","label":"Growth / Performance Chart","type":"chart","required":false,"default_type":"bar","help":"Enter a label and value per data point (e.g. year and revenue). Choose bar, line, pie or donut."},{"name":"market_chart","label":"Market Share / Breakdown Chart","type":"chart","required":false,"default_type":"donut","help":"Great for market share, client mix or revenue split."},{"name":"key_stats","label":"Key Figures","type":"table","required":false,"columns":[{"name":"metric","label":"Metric"},{"name":"value","label":"Value"}],"help":"Headline numbers — e.g. Years in business, Clients served, Projects delivered, Team size."},{"name":"gallery","label":"Image Gallery","type":"gallery","required":false,"help":"Showcase products, projects, your office or team. Up to 12 images."},{"name":"team","label":"Leadership / Team","type":"table","required":false,"columns":[{"name":"name","label":"Name"},{"name":"role","label":"Role / Title"}]},{"name":"milestones","label":"Milestones & Achievements","type":"table","required":false,"columns":[{"name":"year","label":"Year"},{"name":"milestone","label":"Achievement"}]},{"name":"testimonials","label":"Client Testimonials","type":"textarea","required":false,"default":"“Working with this team transformed our business — professional, reliable and genuinely invested in our success.”"},{"name":"contact_info","label":"Contact Information","type":"textarea","required":false,"default":"Address, phone, email and website. Tell prospects exactly how to reach you."},{"name":"website","label":"Website","type":"text","required":false},{"name":"call_to_action","label":"Call to Action","type":"textarea","required":false,"default":"Ready to get started? Contact us today for a free consultation and discover how we can help your business grow."}]}', '[{"q":"What is a company brochure used for?","a":"A premium company brochure introduces your business to prospects, partners and investors in a single polished document — covering who you are, your services, your track record and how to engage you. It is ideal for sales meetings, tenders, trade shows and investor outreach."},{"q":"Can I add my logo, images, charts and tables?","a":"Yes. Add a cover image and an image gallery, showcase performance with bar/line/pie/donut charts, and present services, key figures, team and milestones in clean tables. Your company logo from settings is applied automatically."},{"q":"Can I download this in PDF and Word?","a":"Yes. Export a polished, print-ready PDF on any plan; Pro and Premium can also download an editable Word (DOCX) file. Charts and images are embedded in the PDF automatically."},{"q":"Can I change the fonts, colours and text sizes?","a":"Yes. The Design tab lets you set the font family, text size, heading colour, body-text colour and an accent colour, so the document matches your brand. These apply across the whole document."},{"q":"Are the charts and tables professional and print-ready?","a":"Yes. Charts are generated as crisp vector graphics from the data you enter (bar, line, pie or donut) and render identically on screen and in the downloaded PDF, to a clean international business standard."}]', 1, 1, 'Company Premium Brochure Generator | Invoxaco', 'Design a premium company brochure online — add your logo, cover image, gallery, charts and tables, and control fonts and colours. Export as PDF or Word.', 13
WHERE NOT EXISTS (SELECT 1 FROM document_templates WHERE slug = 'company-premium-brochure-generator');
